import { useState, useRef, useCallback, useEffect, useMemo } from "react";
import axios from "axios";

/* ── Operator HTTP client (port 8001 via Vite proxy) ── */
const opHttp = axios.create({ baseURL: "/operator", timeout: 180000 });

/* ── helpers ──────────────────────────────────────────── */
const ago = (ts) => {
  if (!ts) return "\u2014";
  const d = Date.now() - ts * 1000;
  if (d < 0) return "just now";
  if (d < 60000) return `${Math.floor(d / 1000)}s ago`;
  if (d < 3600000) return `${Math.floor(d / 60000)}m ago`;
  return `${Math.floor(d / 3600000)}h ago`;
};

const statusDot = (ok, size = 8) => (
  <span style={{
    display: "inline-block", width: size, height: size, borderRadius: "50%",
    background: ok ? "var(--v2-green)" : ok === false ? "var(--v2-red)" : "var(--v2-amber)",
    boxShadow: ok ? "0 0 6px rgba(34,197,94,0.5)" : ok === false ? "0 0 6px rgba(239,68,68,0.4)" : "0 0 6px rgba(210,153,34,0.4)",
  }} />
);

const truncStr = (s, max = 200) => (typeof s === "string" && s.length > max ? s.slice(0, max) + "..." : s);

const sevColor = (sev) => sev === "crit" ? "red" : sev === "warn" ? "amber" : "green";

/* ── MiniStat ────────────────────────────────────────── */
function MiniStat({ label, value, t = "blue" }) {
  return (
    <div style={{ padding: "8px 12px", borderRadius: 10, background: "rgba(255,255,255,0.03)", border: "1px solid var(--v2-border)", minWidth: 0 }}>
      <div style={{ fontSize: 10, color: "var(--v2-muted)", marginBottom: 4 }}>{label}</div>
      <div className={`v2-mono v2-${t}`} style={{ fontSize: 18, fontWeight: 700 }}>{value}</div>
    </div>
  );
}

/* ── Tool Result Badge ───────────────────────────────── */
function ToolBadge({ r }) {
  if (r.error) return <span className="v2-mono v2-red" style={{ fontSize: 10 }}>ERR</span>;
  if (r.skipped) return <span className="v2-mono v2-muted" style={{ fontSize: 10 }}>SKIP</span>;
  if (r.result?.ok === false) return <span className="v2-mono v2-red" style={{ fontSize: 10 }}>FAIL</span>;
  return <span className="v2-mono v2-green" style={{ fontSize: 10 }}>OK</span>;
}

/* ════════════════════════════════════════════════════════
   OPERATOR CHAT — SSE streaming + model selector + multi-step
   ════════════════════════════════════════════════════════ */
function OperatorChat({ health, connected }) {
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState("");
  const [loading, setLoading] = useState(false);
  const [streamStatus, setStreamStatus] = useState(""); // "connecting" | "step N" | ""
  const [expandedIdx, setExpandedIdx] = useState(null);
  const [expandedTool, setExpandedTool] = useState(null);
  const [model, setModel] = useState("");
  const [useStreaming, setUseStreaming] = useState(true);
  const scrollRef = useRef(null);
  const inputRef = useRef(null);
  const abortRef = useRef(null);

  const models = health?.available_models || ["gpt-4.1", "gpt-4.1-mini", "gpt-4.1-nano"];
  const defaultModel = health?.default_model || "gpt-4.1";

  const scrollBottom = () => {
    setTimeout(() => scrollRef.current?.scrollTo({ top: scrollRef.current.scrollHeight, behavior: "smooth" }), 80);
  };

  /* ── SSE streaming send ─────────────────────────────── */
  const sendStream = useCallback(async (text) => {
    setLoading(true);
    setStreamStatus("connecting");
    scrollBottom();

    const ctrl = new AbortController();
    abortRef.current = ctrl;

    try {
      const resp = await fetch("/operator/chat/stream", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ message: text, approve: true, model: model || "" }),
        signal: ctrl.signal,
      });

      if (!resp.ok) {
        const errText = await resp.text();
        throw new Error(errText || `HTTP ${resp.status}`);
      }

      const reader = resp.body.getReader();
      const decoder = new TextDecoder();
      let buffer = "";
      const transcript = [];
      let finalText = "";
      let usedModel = model || defaultModel;
      let totalSteps = 0;
      let seconds = 0;

      while (true) {
        const { done, value } = await reader.read();
        if (done) break;
        buffer += decoder.decode(value, { stream: true });

        const lines = buffer.split("\n\n");
        buffer = lines.pop() || "";

        for (const chunk of lines) {
          if (!chunk.startsWith("data: ")) continue;
          try {
            const evt = JSON.parse(chunk.slice(6));
            if (evt.type === "start") {
              usedModel = evt.model || usedModel;
              setStreamStatus(`thinking (${usedModel})`);
            } else if (evt.type === "step") {
              transcript.push(evt.step);
              setStreamStatus(`step ${evt.index + 1}`);
              scrollBottom();
            } else if (evt.type === "done") {
              finalText = evt.final || "";
              totalSteps = evt.steps || transcript.length;
              seconds = evt.seconds || 0;
              usedModel = evt.model || usedModel;
            } else if (evt.type === "error") {
              throw new Error(evt.detail || "Stream error");
            }
          } catch (parseErr) {
            if (parseErr.message !== "Stream error" && !parseErr.message.includes("JSON"))
              throw parseErr;
          }
        }
      }

      setMessages((prev) => [
        ...prev,
        {
          role: "assistant",
          text: finalText || "(no response)",
          seconds, ts: Date.now(), transcript,
          model: usedModel, steps: totalSteps,
        },
      ]);
    } catch (e) {
      if (e.name === "AbortError") {
        setMessages((prev) => [...prev, { role: "error", text: "Request cancelled", ts: Date.now() }]);
      } else {
        const detail = e.message || "Stream failed";
        setMessages((prev) => [...prev, { role: "error", text: detail, ts: Date.now() }]);
      }
    } finally {
      setLoading(false);
      setStreamStatus("");
      abortRef.current = null;
      scrollBottom();
    }
  }, [model, defaultModel]);

  /* ── Standard POST send ─────────────────────────────── */
  const sendPost = useCallback(async (text) => {
    setLoading(true);
    scrollBottom();
    try {
      const r = await opHttp.post("/chat", { message: text, approve: true, model: model || "" });
      const d = r.data;
      setMessages((prev) => [
        ...prev,
        {
          role: "assistant", text: d.final || "(no response)",
          seconds: d.seconds, ts: Date.now(), transcript: d.transcript,
          model: d.model || defaultModel, steps: d.steps || 0,
        },
      ]);
    } catch (e) {
      const detail = e.response?.data?.detail || e.message || "Request failed";
      setMessages((prev) => [...prev, { role: "error", text: detail, ts: Date.now() }]);
    } finally {
      setLoading(false);
      scrollBottom();
    }
  }, [model, defaultModel]);

  const send = useCallback(async () => {
    const text = input.trim();
    if (!text || loading) return;
    setInput("");
    setMessages((prev) => [...prev, { role: "user", text, ts: Date.now() }]);
    if (useStreaming) {
      sendStream(text);
    } else {
      sendPost(text);
    }
  }, [input, loading, useStreaming, sendStream, sendPost]);

  const cancel = useCallback(() => {
    abortRef.current?.abort();
  }, []);

  const toggleTranscript = (idx) => setExpandedIdx(expandedIdx === idx ? null : idx);
  const toggleTool = (key) => setExpandedTool(expandedTool === key ? null : key);

  const clearChat = () => {
    setMessages([]);
    setExpandedIdx(null);
    setExpandedTool(null);
  };

  return (
    <div style={{ display: "flex", flexDirection: "column", height: "100%" }}>
      {/* Model selector bar */}
      <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 8, flexWrap: "wrap" }}>
        <span className="v2-muted" style={{ fontSize: 10, fontWeight: 600 }}>MODEL</span>
        <select
          value={model || defaultModel}
          onChange={(e) => setModel(e.target.value)}
          style={{
            padding: "4px 8px", borderRadius: 6, fontSize: 11,
            background: "rgba(255,255,255,0.06)", border: "1px solid var(--v2-border)",
            color: "var(--v2-text)", fontFamily: "'JetBrains Mono', monospace",
            cursor: "pointer",
          }}
        >
          {models.map((m) => (
            <option key={m} value={m}>{m}{m === defaultModel ? " (default)" : ""}</option>
          ))}
        </select>
        <label style={{ display: "flex", alignItems: "center", gap: 4, cursor: "pointer", fontSize: 10 }}>
          <input
            type="checkbox" checked={useStreaming}
            onChange={(e) => setUseStreaming(e.target.checked)}
            style={{ accentColor: "var(--v2-blue)" }}
          />
          <span className="v2-muted">Stream</span>
        </label>
        <span className="v2-muted" style={{ fontSize: 10 }}>
          {connected ? "OpenAI API" : "Disconnected"}
        </span>
        <div style={{ flex: 1 }} />
        <button className="v2-btn" onClick={clearChat}
          style={{ fontSize: 10, padding: "3px 8px", opacity: messages.length ? 1 : 0.3 }}
          disabled={!messages.length}>
          Clear
        </button>
      </div>

      {/* Messages */}
      <div ref={scrollRef} style={{
        flex: 1, overflowY: "auto", padding: "10px 12px",
        borderRadius: 10, background: "rgba(0,0,0,0.3)", border: "1px solid var(--v2-border)",
        marginBottom: 12,
      }}>
        {messages.length === 0 && (
          <div className="v2-muted" style={{ textAlign: "center", marginTop: 64, fontSize: 13 }}>
            No messages yet. Try:<br />
            <span className="v2-mono" style={{ fontSize: 11, opacity: 0.7 }}>"check system health"</span> or{" "}
            <span className="v2-mono" style={{ fontSize: 11, opacity: 0.7 }}>"restart aura-frontend service"</span><br />
            <span className="v2-mono" style={{ fontSize: 11, opacity: 0.7 }}>"read ~/operator/config/operator.yaml and report status"</span>
          </div>
        )}
        {messages.map((m, i) => (
          <div key={i} style={{ marginBottom: 12 }}>
            <div style={{
              padding: "8px 12px", borderRadius: 10,
              maxWidth: "92%",
              marginLeft: m.role === "user" ? "auto" : 0,
              background: m.role === "user"
                ? "rgba(96,165,250,0.12)"
                : m.role === "error"
                  ? "rgba(239,68,68,0.12)"
                  : "rgba(255,255,255,0.04)",
              border: `1px solid ${m.role === "error" ? "var(--v2-red)" : "var(--v2-border)"}`,
            }}>
              {/* Header */}
              <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 4 }}>
                <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
                  <span className={`v2-mono v2-${m.role === "user" ? "blue" : m.role === "error" ? "red" : "green"}`}
                    style={{ fontSize: 10, fontWeight: 700, textTransform: "uppercase" }}>
                    {m.role === "user" ? "You" : m.role === "error" ? "Error" : "Operator"}
                  </span>
                  {m.model && (
                    <span className="v2-mono v2-muted" style={{ fontSize: 10, padding: "1px 4px", borderRadius: 6, background: "rgba(255,255,255,0.05)" }}>
                      {m.model}
                    </span>
                  )}
                </div>
                <div style={{ display: "flex", gap: 8, alignItems: "center" }}>
                  {m.steps > 1 && <span className="v2-mono v2-blue" style={{ fontSize: 10 }}>{m.steps} steps</span>}
                  {m.seconds != null && <span className="v2-mono v2-muted" style={{ fontSize: 10 }}>{m.seconds}s</span>}
                  {m.transcript && m.transcript.length > 0 && (
                    <button onClick={() => toggleTranscript(i)} className="v2-btn"
                      style={{ fontSize: 10, padding: "2px 6px", lineHeight: 1.2, background: expandedIdx === i ? "rgba(96,165,250,0.15)" : undefined }}>
                      {expandedIdx === i ? "Hide" : "Steps"} ({m.transcript.length})
                    </button>
                  )}
                </div>
              </div>
              {/* Message text */}
              <div style={{ fontSize: 13, whiteSpace: "pre-wrap", wordBreak: "break-word", lineHeight: 1.6 }}>
                {m.text}
              </div>
            </div>

            {/* Transcript Viewer */}
            {expandedIdx === i && m.transcript && (
              <div style={{
                marginTop: 4, marginLeft: 12, padding: "8px 10px",
                borderRadius: 10, background: "rgba(0,0,0,0.3)", border: "1px solid var(--v2-border)",
                fontSize: 10, maxHeight: 400, overflowY: "auto",
              }}>
                {m.transcript.map((step, si) => (
                  <div key={si} style={{ marginBottom: 12, paddingBottom: 8, borderBottom: si < m.transcript.length - 1 ? "1px solid rgba(255,255,255,0.06)" : "none" }}>
                    <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 4 }}>
                      <span className="v2-mono v2-blue" style={{ fontSize: 10, fontWeight: 700, padding: "1px 5px", borderRadius: 6, background: "rgba(96,165,250,0.1)" }}>
                        Step {si + 1}
                      </span>
                      {step.model?.actions?.length > 0 && (
                        <span className="v2-mono v2-amber" style={{ fontSize: 10 }}>
                          {step.model.actions.length} action{step.model.actions.length > 1 ? "s" : ""}
                        </span>
                      )}
                      {step.error && <span className="v2-mono v2-red" style={{ fontSize: 10 }}>LLM Error</span>}
                    </div>

                    {step.model?.thought && (
                      <div style={{ color: "var(--v2-muted)", marginBottom: 4, paddingLeft: 8 }}>
                        <span style={{ fontWeight: 600, color: "var(--v2-text)", opacity: 0.6 }}>Thought: </span>
                        {step.model.thought}
                      </div>
                    )}

                    {step.model?.actions?.map((a, ai) => {
                      const toolKey = `${si}-${ai}`;
                      const result = step.results?.[ai];
                      return (
                        <div key={ai} style={{ marginLeft: 8, marginBottom: 4 }}>
                          <div
                            onClick={() => toggleTool(toolKey)}
                            style={{ display: "flex", alignItems: "center", gap: 8, cursor: "pointer", padding: "2px 4px", borderRadius: 6, background: "rgba(255,255,255,0.02)" }}
                          >
                            <span className="v2-mono v2-amber" style={{ fontSize: 10, fontWeight: 600 }}>[{a.tool}]</span>
                            <span className="v2-mono" style={{ fontSize: 10, color: "var(--v2-text)", opacity: 0.8, flex: 1, overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>
                              {a.cmd || a.path || a.endpoint || a.prompt || a.k || ""}
                            </span>
                            {result && <ToolBadge r={result} />}
                            <span className="v2-muted" style={{ fontSize: 10 }}>{expandedTool === toolKey ? "\u25BC" : "\u25B6"}</span>
                          </div>

                          {expandedTool === toolKey && result && (
                            <div style={{
                              marginTop: 4, marginLeft: 12, padding: "6px 8px",
                              borderRadius: 6, background: "rgba(0,0,0,0.25)", border: "1px solid var(--v2-border)",
                              maxHeight: 200, overflowY: "auto", fontSize: 10,
                            }}>
                              {result.error && <div className="v2-mono v2-red" style={{ whiteSpace: "pre-wrap" }}>{result.error}</div>}
                              {result.skipped && <div className="v2-mono v2-muted">(skipped — approve=false)</div>}
                              {typeof result.result === "string" && (
                                <pre className="v2-mono" style={{ whiteSpace: "pre-wrap", wordBreak: "break-all", color: "var(--v2-text)", margin: 0, opacity: 0.8 }}>
                                  {truncStr(result.result, 3000)}
                                </pre>
                              )}
                              {typeof result.result === "object" && result.result && (
                                <pre className="v2-mono" style={{ whiteSpace: "pre-wrap", wordBreak: "break-all", color: "var(--v2-text)", margin: 0, opacity: 0.8 }}>
                                  {truncStr(JSON.stringify(result.result, null, 2), 3000)}
                                </pre>
                              )}
                              {result.v !== undefined && (
                                <div className="v2-mono" style={{ color: "var(--v2-text)" }}>
                                  <span className="v2-muted">value: </span>{result.v ?? "(null)"}
                                </div>
                              )}
                            </div>
                          )}
                        </div>
                      );
                    })}

                    {step.model?.final && (
                      <div style={{ marginLeft: 8, marginTop: 4, color: "var(--v2-green)", fontSize: 10 }}>
                        <span style={{ fontWeight: 600, opacity: 0.7 }}>Final: </span>
                        {truncStr(step.model.final, 500)}
                      </div>
                    )}
                  </div>
                ))}
              </div>
            )}
          </div>
        ))}

        {/* Loading / streaming indicator */}
        {loading && (
          <div style={{
            padding: "10px 14px", fontSize: 13, display: "flex", alignItems: "center", gap: 8,
            background: "rgba(96,165,250,0.06)", borderRadius: 10, border: "1px solid rgba(96,165,250,0.15)",
          }}>
            <span style={{ display: "flex", gap: 4 }}>
              {[0, 1, 2].map((i) => (
                <span key={i} className="v2-blue" style={{
                  width: 6, height: 6, borderRadius: "50%", display: "inline-block",
                  animation: `pulse 1.4s ease-in-out ${i * 0.2}s infinite`,
                  opacity: 0.6,
                }} />
              ))}
            </span>
            <span className="v2-muted" style={{ fontSize: 11 }}>
              {streamStatus ? `Streaming: ${streamStatus}` : `Operator is thinking (${model || defaultModel})...`}
            </span>
            {useStreaming && (
              <button className="v2-btn" onClick={cancel} style={{ fontSize: 10, padding: "2px 8px", marginLeft: "auto" }}>
                Cancel
              </button>
            )}
          </div>
        )}
      </div>

      {/* Input bar */}
      <div style={{ display: "flex", gap: 8, flexShrink: 0 }}>
        <input
          ref={inputRef}
          value={input}
          onChange={(e) => setInput(e.target.value)}
          onKeyDown={(e) => {
            if (e.key === "Enter" && !e.shiftKey) { e.preventDefault(); send(); }
          }}
          placeholder="Ask the operator agent..."
          disabled={loading || connected !== true}
          autoComplete="off"
          style={{
            flex: 1, padding: "10px 14px", borderRadius: 10, fontSize: 13,
            background: "rgba(255,255,255,0.04)", border: "1px solid var(--v2-border)",
            color: "var(--v2-text)", outline: "none", fontFamily: "'JetBrains Mono', monospace",
            minHeight: 44, minWidth: 0,
          }}
        />
        <button className="v2-btn" onClick={send} disabled={loading || !input.trim() || connected !== true}
          style={{ padding: "10px clamp(12px, 2vw, 20px)", fontSize: 13, fontWeight: 600, minHeight: 44, flexShrink: 0 }}>
          {loading ? "..." : "Send"}
        </button>
      </div>
    </div>
  );
}

/* ════════════════════════════════════════════════════════
   BRAIN STATUS PANEL
   ════════════════════════════════════════════════════════ */
function BrainPanel({ connected }) {
  const [brain, setBrain] = useState(null);
  const [expanded, setExpanded] = useState(false);
  const [clearing, setClearing] = useState(false);

  useEffect(() => {
    if (!connected) return;
    let active = true;
    const poll = async () => {
      try {
        const r = await opHttp.get("/brain/status");
        if (active) setBrain(r.data);
      } catch { /* ignore */ }
    };
    poll();
    const iv = setInterval(poll, 15000);
    return () => { active = false; clearInterval(iv); };
  }, [connected]);

  const clearEscalation = async () => {
    setClearing(true);
    try {
      await opHttp.post("/brain/clear");
      const r = await opHttp.get("/brain/status");
      setBrain(r.data);
    } catch { /* ignore */ }
    setClearing(false);
  };

  if (!brain) {
    return (
      <div className="v2-card">
        <div className="v2-ct">Brain Monitor</div>
        <div className="v2-muted" style={{ fontSize: 11 }}>Loading brain status...</div>
      </div>
    );
  }

  const sev = brain.last_severity || "info";
  const issueCount = brain.issues?.total || 0;
  const critCount = brain.issues?.crit || 0;
  const warnCount = brain.issues?.warn || 0;
  const cycles = brain.recent_cycles || [];
  const recentPlans = cycles.filter((c) => c.kind === "plan").slice(0, 5);

  return (
    <div className="v2-card" style={{
      border: critCount > 0 ? "1px solid rgba(239,68,68,0.25)" : "1px solid var(--v2-border)",
      background: critCount > 0 ? "rgba(239,68,68,0.03)" : undefined,
    }}>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 8 }}>
        <div className="v2-ct" style={{ margin: 0 }}>Brain Monitor</div>
        <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
          {statusDot(brain.brain_active, 7)}
          <span className="v2-mono" style={{ fontSize: 10, color: brain.brain_active ? "var(--v2-green)" : "var(--v2-red)" }}>
            {brain.brain_active ? "Active" : "Down"}
          </span>
        </div>
      </div>

      {/* Status row */}
      <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr 1fr 1fr", gap: 8, marginBottom: 8 }}>
        <div style={{ textAlign: "center", padding: "4px 0" }}>
          <div className="v2-muted" style={{ fontSize: 10 }}>Severity</div>
          <div className={`v2-mono v2-${sevColor(sev)}`} style={{ fontSize: 13, fontWeight: 700, textTransform: "uppercase" }}>{sev}</div>
        </div>
        <div style={{ textAlign: "center", padding: "4px 0" }}>
          <div className="v2-muted" style={{ fontSize: 10 }}>Issues</div>
          <div className={`v2-mono v2-${issueCount > 0 ? "amber" : "green"}`} style={{ fontSize: 13, fontWeight: 700 }}>{issueCount}</div>
        </div>
        <div style={{ textAlign: "center", padding: "4px 0" }}>
          <div className="v2-muted" style={{ fontSize: 10 }}>Critical</div>
          <div className={`v2-mono v2-${critCount > 0 ? "red" : "green"}`} style={{ fontSize: 13, fontWeight: 700 }}>{critCount}</div>
        </div>
        <div style={{ textAlign: "center", padding: "4px 0" }}>
          <div className="v2-muted" style={{ fontSize: 10 }}>Warnings</div>
          <div className={`v2-mono v2-${warnCount > 0 ? "amber" : "green"}`} style={{ fontSize: 13, fontWeight: 700 }}>{warnCount}</div>
        </div>
      </div>

      {/* Recent cycles */}
      {recentPlans.length > 0 && (
        <div style={{ marginBottom: 8 }}>
          <div className="v2-muted" style={{ fontSize: 10, fontWeight: 600, marginBottom: 4 }}>RECENT CYCLES</div>
          {recentPlans.map((c, i) => (
            <div key={i} style={{
              display: "flex", alignItems: "center", gap: 8, padding: "3px 0",
              borderBottom: i < recentPlans.length - 1 ? "1px solid rgba(255,255,255,0.04)" : "none",
            }}>
              <span className={`v2-mono v2-${sevColor(c.severity)}`} style={{ fontSize: 10, fontWeight: 600, minWidth: 32, textTransform: "uppercase" }}>
                {c.severity}
              </span>
              <span className="v2-mono" style={{ fontSize: 10, flex: 1, overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap", opacity: 0.8 }}>
                {c.summary || "\u2014"}
              </span>
              <span className="v2-mono v2-muted" style={{ fontSize: 10 }}>
                {c.actions_count > 0 ? `${c.actions_count} act` : ""}
              </span>
            </div>
          ))}
        </div>
      )}

      {/* Persistent issues detail */}
      {issueCount > 0 && (
        <div style={{ marginBottom: 8 }}>
          <button className="v2-btn" onClick={() => setExpanded(!expanded)}
            style={{ fontSize: 10, padding: "2px 8px", marginBottom: 4 }}>
            {expanded ? "Hide Issues" : `Show Issues (${issueCount})`}
          </button>
          {expanded && (
            <div style={{
              maxHeight: 180, overflowY: "auto", padding: "6px 8px",
              borderRadius: 6, background: "rgba(0,0,0,0.2)", border: "1px solid var(--v2-border)", fontSize: 10,
            }}>
              {Object.entries(brain.issues?.details || {}).map(([key, info]) => (
                <div key={key} style={{ padding: "3px 0", borderBottom: "1px solid rgba(255,255,255,0.04)" }}>
                  <div style={{ display: "flex", justifyContent: "space-between" }}>
                    <span className={`v2-mono v2-${sevColor(info.severity)}`} style={{ fontWeight: 600 }}>
                      {key.replaceAll("_", " ")}
                    </span>
                    <span className="v2-mono v2-muted">x{info.count}</span>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      )}

      {/* Actions */}
      <div style={{ display: "flex", gap: 8 }}>
        <button className="v2-btn" onClick={clearEscalation} disabled={clearing || !connected}
          style={{ fontSize: 10, padding: "5px 10px" }}>
          {clearing ? "..." : "Clear Escalation State"}
        </button>
      </div>
    </div>
  );
}

/* ════════════════════════════════════════════════════════
   PAGE: Operator Control
   ════════════════════════════════════════════════════════ */
export default function OperatorControl() {
  const [health, setHealth] = useState(null);
  const [opState, setOpState] = useState(null);
  const [connected, setConnected] = useState(null);
  const [killLoading, setKillLoading] = useState(false);
  const [taskLoading, setTaskLoading] = useState(false);
  const [reconnectIn, setReconnectIn] = useState(0);

  /* ── Poll operator health + state ───────────────────── */
  useEffect(() => {
    let active = true;
    let failCount = 0;

    const poll = async () => {
      try {
        const [h, s] = await Promise.all([
          opHttp.get("/health"),
          opHttp.get("/state"),
        ]);
        if (!active) return;
        setHealth(h.data);
        setOpState(s.data);
        setConnected(true);
        failCount = 0;
        setReconnectIn(0);
      } catch {
        if (!active) return;
        failCount++;
        setConnected(false);
        const backoff = Math.min(failCount * 5, 30);
        setReconnectIn(backoff);
      }
    };
    poll();
    const iv = setInterval(poll, 10000);
    return () => { active = false; clearInterval(iv); };
  }, []);

  /* ── Kill switch toggle ─────────────────────────────── */
  const toggleKill = async () => {
    if (!health) return;
    const newVal = !health.kill_switch;
    if (newVal && !window.confirm("Activate KILL SWITCH? This will halt all autonomous operations.")) return;
    setKillLoading(true);
    try {
      const r = await opHttp.post("/kill", { kill_switch: newVal });
      setHealth((prev) => ({ ...prev, kill_switch: r.data.kill_switch }));
    } catch { /* ignore */ }
    setKillLoading(false);
  };

  /* ── Enqueue task ───────────────────────────────────── */
  const enqueueTask = async (kind) => {
    setTaskLoading(true);
    try {
      await opHttp.post("/tasks", { kind, requires_approval: false });
      const s = await opHttp.get("/state");
      setOpState(s.data);
    } catch { /* ignore */ }
    setTaskLoading(false);
  };

  /* ── Trigger train/max ──────────────────────────────── */
  const runTrainMax = async () => {
    if (!window.confirm("Run full Train Max cycle? (scan + fix + restart + verify)")) return;
    setTaskLoading(true);
    try {
      await opHttp.post("/train/max");
      const s = await opHttp.get("/state");
      setOpState(s.data);
    } catch { /* ignore */ }
    setTaskLoading(false);
  };

  /* ── Clean stale tasks ──────────────────────────────── */
  const cleanTasks = async () => {
    try {
      await opHttp.post("/tasks/cleanup", { action: "clear_stale" });
      const s = await opHttp.get("/state");
      setOpState(s.data);
    } catch { /* ignore */ }
  };

  /* ── Derived data ───────────────────────────────────── */
  const killActive = health?.kill_switch === true;
  const tasks = opState?.tasks || [];
  const recentTasks = tasks.slice(0, 12);
  const runningCount = tasks.filter((t) => t.status === "running").length;
  const queuedCount = tasks.filter((t) => t.status === "queued").length;
  const doneCount = tasks.filter((t) => t.status === "done").length;
  const failedCount = tasks.filter((t) => t.status === "failed").length;
  const lastScan = opState?.last_scan;
  const lastFix = opState?.last_fix;
  const lastRestart = opState?.last_restart;
  const lastEscalation = opState?.last_escalation;

  const scanRepos = lastScan?.repos || [];
  const totalMissing = useMemo(() => {
    if (!lastScan?.results) return 0;
    return lastScan.results.reduce((sum, r) => sum + (r.counts?.missing_routes || 0), 0);
  }, [lastScan]);

  const totalUnused = useMemo(() => {
    if (!lastScan?.results) return 0;
    return lastScan.results.reduce((sum, r) => sum + (r.counts?.unused_routes || 0), 0);
  }, [lastScan]);

  const brainIssues = health?.brain_issues || 0;

  return (
    <div role="main" aria-label="Operator Control" data-mode="operator" style={{ fontFamily: "'JetBrains Mono', monospace" }}>
      {/* ── Header ──────────────────────────────────────── */}
      <div className="v2-pagehead">
        <div>
          <h1 className="v2-h1">Operator Control</h1>
          <div className="v2-muted" style={{ fontSize: 11 }}>
            Agent chat, brain monitor, kill switch, task queue, scan results
            {health?.version && <span className="v2-mono" style={{ marginLeft: 8, opacity: 0.5 }}>v{health.version}</span>}
          </div>
        </div>
        <div className="v2-row" style={{ gap: 8, alignItems: "center" }}>
          {statusDot(connected === true)}
          <span className="v2-pill v2-mono" style={{ fontSize: 11 }}>
            {connected === true ? "Connected" : connected === false ? `Offline${reconnectIn ? ` (retry ${reconnectIn}s)` : ""}` : "Checking..."}
          </span>
          {health?.llm_mode && (
            <span className="v2-pill v2-mono v2-blue" style={{ fontSize: 10 }}>
              {health.llm_mode.toUpperCase()}
            </span>
          )}
          {brainIssues > 0 && (
            <span className="v2-pill v2-mono v2-amber" style={{ fontSize: 10 }}>
              Brain: {brainIssues} issues
            </span>
          )}
          <span className={`v2-pill v2-mono v2-${killActive ? "red" : "green"}`} style={{ fontSize: 11 }}>
            Kill: {killActive ? "ON" : "OFF"}
          </span>
        </div>
      </div>

      {/* ── Row 1: Top Stats ─────────────────────────────── */}
      <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(100px, 1fr))", gap: 8, marginBottom: 12 }}>
        <MiniStat label="Status" value={connected ? "Online" : "Offline"} t={connected ? "green" : "red"} />
        <MiniStat label="Kill Switch" value={killActive ? "ACTIVE" : "OFF"} t={killActive ? "red" : "green"} />
        <MiniStat label="Running" value={runningCount} t={runningCount > 0 ? "blue" : "green"} />
        <MiniStat label="Queued" value={queuedCount} t={queuedCount > 0 ? "amber" : "green"} />
        <MiniStat label="Done" value={doneCount} t="green" />
        <MiniStat label="Failed" value={failedCount} t={failedCount > 0 ? "red" : "green"} />
        <MiniStat label="Brain Issues" value={brainIssues} t={brainIssues > 0 ? "amber" : "green"} />
        <MiniStat label="Missing Routes" value={totalMissing} t={totalMissing > 0 ? "amber" : "green"} />
      </div>

      {/* ── Row 2: Chat (left 7) | Controls (right 5) ──── */}
      <div className="v2-grid" style={{ marginBottom: 12 }}>
        {/* Operator Chat */}
        <div className="v2-card" style={{ gridColumn: "span 7", display: "flex", flexDirection: "column", minHeight: "min(520px, 60vh)" }}>
          <div className="v2-ct" style={{ marginBottom: 4 }}>Operator Agent Chat</div>
          <div className="v2-muted" style={{ fontSize: 10, marginBottom: 8 }}>
            OpenAI ({health?.default_model || "..."}) via port 8001 &middot; SSE streaming &middot; Can read/write files, run shell, manage infra
          </div>
          <div style={{ flex: 1, display: "flex", flexDirection: "column" }}>
            <OperatorChat health={health} connected={connected} />
          </div>
        </div>

        {/* Controls Panel */}
        <div style={{ gridColumn: "span 5", display: "flex", flexDirection: "column", gap: 12 }}>
          {/* Kill Switch */}
          <div className="v2-card" style={{
            border: killActive ? "1px solid rgba(239,68,68,0.3)" : "1px solid var(--v2-border)",
            background: killActive ? "rgba(239,68,68,0.06)" : "rgba(255,255,255,0.04)",
          }}>
            <div className="v2-ct">Kill Switch</div>
            <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between" }}>
              <div>
                <div style={{ fontSize: 13, fontWeight: 700, color: killActive ? "var(--v2-red)" : "var(--v2-green)" }}>
                  {killActive ? "KILL SWITCH ACTIVE \u2014 All autonomous actions halted" : "System running \u2014 autonomous mode enabled"}
                </div>
                <div className="v2-muted" style={{ fontSize: 10, marginTop: 4 }}>
                  Toggles all scans, auto-fixes, and restarts
                </div>
              </div>
              <button
                className={`v2-btn ${killActive ? "" : "danger"}`}
                onClick={toggleKill}
                disabled={killLoading || connected !== true}
                style={{ padding: "10px 20px", fontSize: 13, fontWeight: 700, minWidth: 100 }}
              >
                {killLoading ? "..." : killActive ? "Disable Kill" : "Activate Kill"}
              </button>
            </div>
          </div>

          {/* Brain Monitor */}
          <BrainPanel connected={connected} />

          {/* Actions */}
          <div className="v2-card">
            <div className="v2-ct">Actions</div>
            <div style={{ display: "flex", gap: 8, flexWrap: "wrap" }}>
              <button className="v2-btn" disabled={taskLoading || connected !== true} onClick={() => enqueueTask("scan")} style={{ fontSize: 11, padding: "8px 14px" }}>
                Enqueue Scan
              </button>
              <button className="v2-btn" disabled={taskLoading || connected !== true} onClick={() => enqueueTask("train_max")} style={{ fontSize: 11, padding: "8px 14px" }}>
                Enqueue Train Max
              </button>
              <button className="v2-btn" disabled={taskLoading || connected !== true} onClick={runTrainMax} style={{ fontSize: 11, padding: "8px 14px", fontWeight: 600 }}>
                Run Train Max Now
              </button>
              <button className="v2-btn" disabled={connected !== true} onClick={cleanTasks} style={{ fontSize: 10, padding: "6px 10px", opacity: 0.7 }}>
                Clean Stale Tasks
              </button>
            </div>
          </div>

          {/* Last Scan Summary */}
          <div className="v2-card">
            <div className="v2-ct">Last Scan</div>
            {lastScan ? (
              <div style={{ fontSize: 11 }}>
                <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 4 }}>
                  <span className="v2-muted">Time</span>
                  <span className="v2-mono">{ago(lastScan.ts)}</span>
                </div>
                <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 4 }}>
                  <span className="v2-muted">Repos</span>
                  <span className="v2-mono">{scanRepos.join(", ") || "\u2014"}</span>
                </div>
                {lastScan.results?.map((r, i) => (
                  <div key={i} style={{ marginTop: 8, padding: "6px 8px", borderRadius: 6, background: "rgba(255,255,255,0.02)", border: "1px solid var(--v2-border)" }}>
                    <div style={{ fontSize: 10, fontWeight: 600, marginBottom: 4 }}>{r.repo?.split("/").pop()}</div>
                    <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 4, fontSize: 10 }}>
                      <span className="v2-muted">Files scanned</span>
                      <span className="v2-mono" style={{ textAlign: "right" }}>{r.counts?.files_scanned}</span>
                      <span className="v2-muted">API calls</span>
                      <span className="v2-mono" style={{ textAlign: "right" }}>{r.counts?.distinct_api_calls}</span>
                      <span className="v2-muted">Routes defined</span>
                      <span className="v2-mono" style={{ textAlign: "right" }}>{r.counts?.distinct_fastapi_routes}</span>
                      <span className="v2-muted">Missing routes</span>
                      <span className={`v2-mono v2-${r.counts?.missing_routes > 0 ? "amber" : "green"}`} style={{ textAlign: "right" }}>{r.counts?.missing_routes}</span>
                      <span className="v2-muted">Unused routes</span>
                      <span className={`v2-mono v2-${r.counts?.unused_routes > 0 ? "amber" : "green"}`} style={{ textAlign: "right" }}>{r.counts?.unused_routes}</span>
                    </div>
                  </div>
                ))}
              </div>
            ) : (
              <div className="v2-muted" style={{ fontSize: 11 }}>No scan results yet.</div>
            )}
          </div>

          {/* Activity Log */}
          <div className="v2-card">
            <div className="v2-ct">Activity</div>
            <div style={{ fontSize: 10 }}>
              {[
                { label: "Last Fix", data: lastFix, key: "fix" },
                { label: "Last Restart", data: lastRestart, key: "restart" },
                { label: "Last Escalation", data: lastEscalation, key: "escalation" },
              ].map(({ label, data, key }) => (
                <div key={key} style={{ display: "flex", justifyContent: "space-between", padding: "4px 0", borderBottom: "1px solid var(--v2-border)" }}>
                  <span className="v2-muted">{label}</span>
                  <span className="v2-mono">
                    {data ? (
                      <>
                        {ago(data.ts)}{" "}
                        {data.ok === true && <span className="v2-green">OK</span>}
                        {data.ok === false && <span className="v2-red">FAIL</span>}
                      </>
                    ) : "\u2014"}
                  </span>
                </div>
              ))}
            </div>
          </div>
        </div>
      </div>

      {/* ── Row 3: Task Queue ────────────────────────────── */}
      <div className="v2-grid">
        <div className="v2-card wide">
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
            <div className="v2-ct">Task Queue ({recentTasks.length})</div>
          </div>
          {recentTasks.length === 0 ? (
            <div className="v2-muted" style={{ fontSize: 11, padding: 12, textAlign: "center" }}>No tasks in queue.</div>
          ) : (
            <div className="v2-table" style={{ marginTop: 4 }}>
              <div className="v2-thead" style={{ gridTemplateColumns: "160px 80px 80px 1fr 100px", fontSize: 10 }}>
                <span>Task ID</span>
                <span>Kind</span>
                <span>Status</span>
                <span>Error</span>
                <span style={{ textAlign: "right" }}>Created</span>
              </div>
              {recentTasks.map((t) => {
                const statusColor = t.status === "done" ? "green" : t.status === "failed" ? "red" : t.status === "running" ? "blue" : "amber";
                return (
                  <div key={t.task_id} className="v2-tr" style={{ gridTemplateColumns: "160px 80px 80px 1fr 100px", padding: "4px 12px" }}>
                    <span className="v2-mono" style={{ fontSize: 10 }}>{t.task_id}</span>
                    <span style={{ fontSize: 11 }}>{t.kind}</span>
                    <span className={`v2-mono v2-${statusColor}`} style={{ fontSize: 11, fontWeight: 600, textTransform: "uppercase" }}>{t.status}</span>
                    <span className="v2-mono v2-red" style={{ fontSize: 10, overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>
                      {t.error || "\u2014"}
                    </span>
                    <span className="v2-mono v2-muted" style={{ textAlign: "right", fontSize: 10 }}>{ago(t.created_ts)}</span>
                  </div>
                );
              })}
            </div>
          )}
        </div>
      </div>
    </div>
  );
}
